const ids = $.steps.extractIds.output.messageIds || [];
const iterations = $.steps.fetchEmailDetails.response.iterations || [];
const faqResp = $.steps.readFaq.response || {};
const faqValues = faqResp.values || [];

let faqText = '';
faqValues.slice(1).forEach((row, i) => {
  if (row[0] && row[1]) {
    faqText += 'Q: ' + row[0] + '\nA: ' + row[1] + '\n\n';
  }
});

let emails = [];
ids.forEach((id, i) => {
  let subject = 'Unknown';
  let from = 'Unknown';
  let body = '';
  if (iterations[i] && iterations[i].getOne && iterations[i].getOne.response) {
    const msg = iterations[i].getOne.response;
    body = msg.snippet || '';
    const headers = msg.payload && msg.payload.headers ? msg.payload.headers : [];
    headers.forEach(h => {
      if (h.name === 'Subject') subject = h.value || 'No Subject';
      if (h.name === 'From') from = h.value || 'Unknown';
    });
  }
  emails.push({ id, subject, from, body: body.slice(0, 500) });
});

let emailText = '';
emails.forEach((e, i) => {
  emailText += '--- EMAIL ' + (i + 1) + ' ---\n';
  emailText += 'ID: ' + e.id + '\n';
  emailText += 'From: ' + e.from + '\n';
  emailText += 'Subject: ' + e.subject + '\n';
  emailText += 'Body: ' + e.body + '\n\n';
});

return { emailText, faqText: faqText.slice(0, 10000), emails, emailCount: emails.length };

const d = $.steps.compileData.output;
const company = $.input.companyName;
const tone = $.input.supportTone;
let prompt = 'You are a ' + tone + ' customer support agent for ' + company + '. Draft reply suggestions for each support email using the FAQ knowledge base.\n\n';
prompt += 'FAQ KNOWLEDGE BASE:\n' + d.faqText + '\n';
prompt += 'SUPPORT EMAILS (' + d.emailCount + '):\n' + d.emailText + '\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Draft a reply for each email\n';
prompt += '- Use the FAQ when relevant\n';
prompt += '- Be ' + tone + '\n';
prompt += '- Flag emails that need human escalation\n';
prompt += '- Keep replies concise but thorough\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "replies": [{\n';
prompt += '    "emailId": "original email ID",\n';
prompt += '    "from": "sender",\n';
prompt += '    "subject": "original subject",\n';
prompt += '    "replySubject": "Re: subject",\n';
prompt += '    "replyBody": "draft reply text",\n';
prompt += '    "category": "billing|technical|general|feedback",\n';
prompt += '    "needsEscalation": false,\n';
prompt += '    "escalationReason": ""\n';
prompt += '  }],\n';
prompt += '  "summary": { "total": 0, "escalated": 0, "autoReply": 0 }\n';
prompt += '}';
return { prompt };

let raw = $.steps.aiSupport.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { replies: [], summary: { total: 0, escalated: 0, autoReply: 0 } }; }

const ai = $.steps.parseAI.output;
const replies = ai.replies || [];
const summary = ai.summary || {};

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Support Agent - Draft Replies', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*' + replies.length + ' replies* drafted | *' + (summary.escalated || 0) + '* need escalation' } });
blocks.push({ type: 'divider' });

replies.forEach((r, i) => {
  const icon = r.needsEscalation ? ':warning:' : ':envelope:';
  let text = icon + ' *' + (r.subject || 'No Subject') + '* from ' + (r.from || 'Unknown') + '\n';
  text += '_Category:_ ' + (r.category || 'general');
  if (r.needsEscalation) text += ' | :rotating_light: *ESCALATION: ' + (r.escalationReason || 'Needs human review') + '*';
  text += '\n_Draft:_ ' + (r.replyBody || '').slice(0, 300);
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: text } });
  if (i < replies.length - 1) blocks.push({ type: 'divider' });
});

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Review drafts above and approve for sending | Powered by Gmail + Claude AI' }] });

const fallback = 'Support Agent: ' + replies.length + ' draft replies ready for review';
return { blocks, fallback };
